15	
16	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
17	  amulet: 60,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	const BLOCK_TYPES = new Set(["rune", "moonstone"]);
22	const BLOCK_OF_THREE_BASE = 60;
23	const BLOCK_SIZE = 3;
24	
25	const basePremiumForItem = (item: QuoteItem): number =>
26	  BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
27	
28	const groupByType = (items: QuoteItem[]): Map<string, QuoteItem[]> =>
29	  items.reduce((groups, item) => {
30	    const group = groups.get(item.type) ?? [];
31	    return groups.set(item.type, [...group, item]);
32	  }, new Map<string, QuoteItem[]>());
33	
34	const isHighEnchantment = (item: QuoteItem): boolean =>
35	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
36	
37	const itemSurchargeRate = (item: QuoteItem): number =>
38	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
39	  (isHighEnchantment(item) ? HIGH_ENCHANTMENT_RATE : 0) +
40	  FIRST_INSURANCE_RATE;
41	
42	const itemPremium = (item: QuoteItem): number => {
43	  const base = basePremiumForItem(item);
44	  return base + base * itemSurchargeRate(item);
45	};
46	
47	const isBlockGroup = (type: string, group: QuoteItem[]): boolean =>
48	  BLOCK_TYPES.has(type) && group.length === BLOCK_SIZE;
49	
50	const groupBase = (type: string, group: QuoteItem[]): number =>
51	  isBlockGroup(type, group)
52	    ? BLOCK_OF_THREE_BASE
53	    : group.reduce((sum, item) => sum + basePremiumForItem(item), 0);
54	
55	const groupPremium = (type: string, group: QuoteItem[]): number =>
56	  isBlockGroup(type, group)
57	    ? BLOCK_OF_THREE_BASE * (1 + FIRST_INSURANCE_RATE)
58	    : group.reduce((sum, item) => sum + itemPremium(item), 0);
59	
60	const sumOver = (
61	  items: QuoteItem[],
62	  groupFn: (type: string, group: QuoteItem[]) => number,
63	): number =>
64	  [...groupByType(items)].reduce(
65	    (total, [type, group]) => total + groupFn(type, group),
66	    0,
67	  );
68	
69	const loyaltyDiscount = (customer: Customer, policyBase: number): number =>
70	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
71	
72	const followUpDiscount = (quoteIndex: number, policyBase: number): number =>
73	  quoteIndex > 0 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
74	
75	const quoteStep = (customer: Customer, quoteIndex: number) => (step: Step) => {
76	  const policyBase = sumOver(step.items, groupBase);
77	  const premiumWithSurcharges = sumOver(step.items, groupPremium);
78	  return {
79	    premium:
80	      premiumWithSurcharges -
81	      loyaltyDiscount(customer, policyBase) -
82	      followUpDiscount(quoteIndex, policyBase) +
83	      PROCESSING_FEE,
84	  };
85	};
86	
87	export const runScenario = (scenario: unknown): unknown => {
88	  const { customer, steps } = scenario as Scenario;
89	  let quoteIndex = 0;
90	  const results = steps.map((step) => {
91	    const result = quoteStep(customer, quoteIndex)(step);
92	    if (step.op === "quote") quoteIndex++;
93	    return result;
94	  });
95	  return { results };
96	};
